// Single item from Google Drive Trigger
const file = $('Google Drive Trigger').item.json;
const existing = $input.item.json;

if (existing?.already_ingested === true) return [];

const name = file.name ?? '';

// Parse: "Revisión HUB Decada - POL CAMI - 2026/03/25 13:00 CET - Notas de Gemini"
const geminiMatch = name.match(
  /^(.+?)\s*-\s*(\d{4})\/(\d{2})\/(\d{2})\s+(\d{2}):(\d{2})\s+\w+\s*-\s*Notas de Gemini$/
);

let meetingTitle = name;
let parsedDate = null;
let parsedTimestamp = null;

if (geminiMatch) {
  meetingTitle = geminiMatch[1].trim();
  const [, , year, month, day, hour, minute] = geminiMatch;
  parsedDate = `${year}-${month}-${day}`;
  parsedTimestamp = `${year}-${month}-${day}T${hour}:${minute}:00+01:00`;
}

return [{
  json: {
    drive_file_id: file.id,
    file_name: name,
    document_url: file.webViewLink ?? '',
    modified_time: file.modifiedTime ?? file.createdTime,
    meeting_title: meetingTitle,
    parsed_date: parsedDate,
    parsed_timestamp: parsedTimestamp
  }
}];

const meta = $('Filter ingested + parse title').item.json;
const doc = $input.item.json;

const FREEMAIL = new Set([
  'gmail.com','googlemail.com','outlook.com','hotmail.com','hotmail.es',
  'live.com','yahoo.com','yahoo.es','icloud.com','me.com','mac.com',
  'protonmail.com','proton.me','aol.com','zoho.com','mail.com'
]);

// Extract text content
const contentText = (doc.content ?? '').trim();

// Extract person emails from structured body
const persons = [];
const bodyContent = doc.body?.content ?? [];
for (const block of bodyContent) {
  if (!block.paragraph) continue;
  for (const el of (block.paragraph.elements ?? [])) {
    if (el.person?.personProperties?.email) {
      persons.push({
        email: el.person.personProperties.email.toLowerCase(),
        name: el.person.personProperties.name ?? ''
      });
    }
  }
}

// Collect all participant emails and their domains
const allEmails = persons.map(p => p.email);
const allDomains = [...new Set(
  allEmails
    .map(e => e.split('@')[1])
    .filter(d => d && !FREEMAIL.has(d))
)];

// Freemail participants: keep email for direct lookup
const freemailEmails = persons
  .filter(p => FREEMAIL.has(p.email.split('@')[1] ?? ''))
  .map(p => p.email);

// All lookup values: all emails + domains + freemail emails
const lookupValues = [...new Set([...allEmails, ...allDomains, ...freemailEmails])];

return [{
  json: {
    ...meta,
    content_text: contentText,
    participant_emails: allEmails,
    participant_domains: allDomains,
    freemail_emails: freemailEmails,
    lookup_values: lookupValues
  }
}];

const transcript = $('Extract text + participants').item.json;
const meetingRow = $input.item.json;

const transcriptAt = transcript.parsed_timestamp
  ? transcript.parsed_timestamp
  : transcript.modified_time;

return [{
  json: {
    ...transcript,
    meeting_id: meetingRow?.meeting_id ?? null,
    client_id:  meetingRow?.client_id  ?? null,
    transcript_at: transcriptAt
  }
}];

const transcript = $('Merge meeting_id').item.json;
const fallback = $input.item.json;

const clientId = transcript.client_id || fallback.client_id || null;

return [{
  json: {
    ...transcript,
    client_id: clientId,
    // Clean up internal fields
    lookup_values: undefined,
    participant_emails: undefined,
    participant_domains: undefined,
    freemail_emails: undefined
  }
}];
